  ('aboriginal-e0adf6cd-moex-00106', 'aboriginal-e0adf6cd', 'aboriginal-e0adf6cd-moex-111-856e6567', 'sub-aboriginal-e0adf6cd-01', NULL, 'essay', '許多學校會在交給老師的修課學生名單或點名單中註記某生為原住民
